head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------

scwin.olddata = "";
scwin.eventCnt = 0;
scwin.colId = "";


//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "SD060", compID: "acb_expImpClsCd" }, // 셀렉트
        { grpCd: "OP182", compID: "gr_main2:pchsAdjmStdCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);


    let codeOptions1 = [
        {
            compID: "gr_main2:eqKndCd",
            method: "getGridComboNoSort",
            param1: "CommonEBC",
            param2: "retrieveSysCdTest_hooni",
            param3: [],
            param4: false
        }
    ];
    $c.data.setGauceUtil(codeOptions1);


};

scwin.onUdcCompleted = function() {

    // 작업 단계 콤보 세팅
    $c.sbm.execute(sbm_wrkStpCd);

    // 규격 콤보 세팅
    $c.sbm.execute(sbm_LkStepNo2);


    // 미사용 삭제 프로그램 호출
    $c.gus.cfEnableObj(btn_save, false);
    $c.gus.cfEnableObj(button_grid1,false);
	$c.gus.cfEnableObj(button_grid2,false);
	$c.gus.cfEnableObj(button_grid3,false);
    $c.gus.cfInitObjects(tbl_condition, null);
    ed_cvsslMgntNo.focus();


    ed_arrvlportDtm.setDisplayFormat("####/##/## ##:##");
    ed_deprtportDtm.setDisplayFormat("####/##/## ##:##");


}

//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 조회 f_retrieve
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    ds_LkStepNo2.clearFilter();
    // $c.gus.cfEnableObj(btn_create);

    if (!await $c.gus.cfValidate([ed_cvsslMgntNo, acb_expImpClsCd])) {
        return;
    }

    dma_condition.set("cvsslWrkPlCls", "P");
    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_condition.set("expImpClsCd", acb_expImpClsCd.getValue());

    await $c.sbm.execute(sbm_condition);

};


//-------------------------------------------------------------------------
// 중간 프리폼 데이터셋 조회 완료시
//-------------------------------------------------------------------------
scwin.ds_main1_ondataload = function (e) {

    // 바인딩 or 해당 방법인데 바인딩이 원활하지 않아 해당 방법 사용

    ed_vsslNm.setValue(ds_main1.getCellData(0, "vsslNm"))
    ed_lineNm.setValue(ds_main1.getCellData(0, "lineNm"))
    ed_shpCoNm.setValue(ds_main1.getCellData(0, "shpCoNm"))
    ed_portcnt.setValue(ds_main1.getCellData(0, "portcnt"))
    ed_repKcg.setValue(ds_main1.getCellData(0, "repKcg"))
    ed_wrkPlNm.setValue(ds_main1.getCellData(0, "wrkPlNm"))
    ed_arrvlportDtm.setValue(ds_main1.getCellData(0, "arrvlportDtm"))
    ed_deprtportDtm.setValue(ds_main1.getCellData(0, "deprtportDtm"))

    ed_arrvlportDtm.setDisplayFormat("####/##/## ##:##");
    ed_deprtportDtm.setDisplayFormat("####/##/## ##:##");
    // ed_freeTradRgnYn.setValue(ds_main1.getCellData(0,"freeTradRgnYn"))
    // ed_cvsslCompleteYn.setValue(ds_main1.getCellData(0,"cvsslCompleteYn"))

    if (ds_main1.getTotalRow() >= 1) {
        $c.gus.cfEnableObj(btn_save, true);
        $c.gus.cfEnableObj(button_grid1,true);
        $c.gus.cfEnableObj(button_grid2,true);
        $c.gus.cfEnableObj(button_grid3,true);

    } else if (ds_main1.getTotalRow() == 0) {

        $c.gus.cfEnableObj(btn_save, false);
        $c.gus.cfEnableObj(button_grid1,false);
        $c.gus.cfEnableObj(button_grid2,false);
        $c.gus.cfEnableObj(button_grid3,false);

    }
};





