//-------------------------------------------------------------------------
// 행 추가 f_AddRow
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    ds_LkStepNo2.clearFilter();
    let row1 = ds_main2.getRowPosition();
    let row = ds_main2.insertRow();

    if (ds_main2.getTotalRow() != 1) {
        ds_main2.setCellData(row, "cvsslWrkPlCls", ds_main2.getCellData(row1, "cvsslWrkPlCls"));	// 본선/작업장구분
        ds_main2.setCellData(row, "cvsslMgntNo", ds_main2.getCellData(row1, "cvsslMgntNo"));		// 본선관리번호
        ds_main2.setCellData(row, "impExpClsCd", ds_main2.getCellData(row1, "impExpClsCd"));		// 수출입구분
        ds_main2.setCellData(row, "wrkPlCd", ds_main2.getCellData(row1, "wrkPlCd"));			// 작업장
        ds_main2.setCellData(row, "wrkDt", ds_main2.getCellData(row1, "wrkDt"));			// 작업일자
        ds_main2.setCellData(row, "wrkStDt", ds_main2.getCellData(row1, "wrkStDt"));			// 작업시작일자
        ds_main2.setCellData(row, "wrkStHh", ds_main2.getCellData(row1, "wrkStHh"));			// 작업시작시간
        ds_main2.setCellData(row, "wrkEndDt", ds_main2.getCellData(row1, "wrkEndDt"));			// 작업종료일자
        ds_main2.setCellData(row, "wrkEndHh", ds_main2.getCellData(row1, "wrkEndHh"));			// 작업종료시간
        ds_main2.setCellData(row, "stvWrkIndictNo", ds_main2.getCellData(row1, "stvWrkIndictNo"));	// 하역작업지시번호 
    } else {
        ds_main2.setCellData(row, "cvsslWrkPlCls", "P");			// 본선/작업장구분
        ds_main2.setCellData(row, "cvsslMgntNo", ed_cvsslMgntNo.getValue());		// 본선관리번호
        ds_main2.setCellData(row, "impExpClsCd", acb_expImpClsCd.getValue());				// 수출입구분
        ds_main2.setCellData(row, "wrkPlCd", ds_main1.getCellData(0, "wrkPlCd"));			// 작업장
        ds_main2.setCellData(row, "wrkDt", ds_main1.getCellData(0, "arrvlportDtm").substring(0, 8));	// 작업일자
        ds_main2.setCellData(row, "wrkStDt", ds_main1.getCellData(0, "arrvlportDtm").substring(0, 8));	// 작업시작일자
        ds_main2.setCellData(row, "wrkStHh", ds_main1.getCellData(0, "arrvlportDtm").substring(8, 12));	// 작업시작시간
        ds_main2.setCellData(row, "wrkEndDt", ds_main1.getCellData(0, "deprtportDtm").substring(0, 8));	// 작업종료일자
        ds_main2.setCellData(row, "hveqRsltsRegYn", "0");
    }

    gr_main2.setFocusedCell(row, 1);
}

//-------------------------------------------------------------------------
// 저장 f_mainSave
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function (e) {

    if (ds_main2.getModifiedIndex().length == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, "중기사용료 매출")); // "@은(는) 변경된 사항이 없습니다."
        return;
    }

    // 그리드 validate 수행
    let validArray = [
        {id:"stvWrkIndictNo", name: "작업지시번호", mandatory: true},
        {id:"eqKndCd", name: "중기종류코드", mandatory: true},
        {id:"wrkStpCd", name: "작업단계", mandatory:false},
        {id:"wrkStDt", name: "시작일자", mandatory:true, valid:"date", format: "YYYYMMDD"},
        {id:"wrkEndDt", name: "종료일자", mandatory:true, valid:"date", format: "YYYYMMDD"},
        {id:"wrkStHh", name: "시작시간", mandatory:true, valid:"date", format: "HHmm"},
        {id:"wrkEndHh", name: "종료시간", mandatory:true, valid:"date", format: "HHmm"},
        {id:"pchsAdjmStdCd", name: "적용기준", mandatory:true},
        {id:"adptWt", name: "적용중량", mandatory:false, maxlength : 8.3},
        {id:"adptHhCnt", name: "적용시간", mandatory:false, maxLength : 2}
    ];


    ret = await $c.gus.cfValidateGrid(gr_main2, null, null, validArray, "중기사용료 매출생성");

    if (! await ret) {
        return;
    }

    let dDate = "";

    for (i = 0; i < ds_main2.getTotalRow(); i++) {
        // 시작일자 == 작업일자
        if (ds_main2.getRowStatus(i) != "D") {
            dDate = ds_main2.getCellData(i, "wrkDt");

            if (ds_main2.getCellData(i, "wrkStDt") != dDate) {
                $c.win.alert("시작일자는작업일자와 동일해야 합니다.");
                ds_main2.setRowPosition(i);
                gr_main2.setFocusedCell(i, "wrkStDt");
                return;
            }

            // 작업일와 종료일자의 차이
            let v_daysBetween = $c.date.diffDate(dDate, ds_main2.getCellData(i, "wrkEndDt"));

            if (Number(v_daysBetween) > 1) { // 차이가 1 이상이면
                $c.win.alert("종료일자는 작업일자와 동일하거나 +1일로 입력하시오.");
                ds_main2.setRowPosition(i);
                gr_main2.setFocusedCell(i, "wrkEndDt");
                return;
            }

            // 시작일자보다 종료일자가 작으면
            if (!$c.gus.cfIsAfterDate(ds_main2.getCellData(i, "wrkStDt"), ds_main2.getCellData(i, "wrkEndDt"))) {		// 시작일자와 종료일자 비교하여 시작일자보다 종료일자가 크지 않도록 Check
                $c.win.alert(MSG_CM_ERR_039);	// 시작일자가 종료일자 이전이어야 합니다.
                ds_main2.setRowPosition(i);
                gr_main2.setFocusedCell(i, "wrkStDt");
                return;
            }

            // 시작일자와 종료일자가 같고 시작시간이 종료시간보다 작으면
            if (Number(v_daysBetween) < 1) {
                if (ds_main2.getCellData(i, "wrkEndHh") <= ds_main2.getCellData(i, "wrkStHh")) {
                    $c.win.alert(MSG_CM_ERR_058);	// 시작시간이 종료시간 이전이어야 합니다.
                    ds_main2.setRowPosition(i);
                    gr_main2.setFocusedCell(i, "wrkStHh");
                    return;
                }
            }

            // 적용기준에 따라 필수값 체크
            if (ds_main2.getCellData(i, "pchsAdjmStdCd") == "H") {
                if (ds_main2.getCellData(i, "adptHhCnt") == 0) {
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "적용시간"));
                    ds_main2.setRowPosition(i);
                    gr_main2.setFocusedCell(i, "adptHhCnt");
                    return;
                }
            } else {
                if (ds_main2.getCellData(i, "adptWt") == 0) {
                    $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "적용중량"));
                    ds_main2.setRowPosition(i);
                    gr_main2.setFocusedCell(i, "adptWt");
                    return
                }
            }
        }
    }

    $c.sbm.execute(sbm_main);


};


//-------------------------------------------------------------------------
// 그리드 데이터 조회 완료시
//-------------------------------------------------------------------------
scwin.ds_main2_ondataload = function () {
    if (ds_main2.getTotalRow() != 0) {
        spa_totalRows.setValue(ds_main2.getTotalRow());
        gr_main2.setFocusedCell(0, 1);
        // btn_create.setDisabled(false);
        $c.gus.cfEnableObj(btn_save, true);

    } else {
        $c.win.alert(MSG_CM_WRN_002);
        spa_totalRows.setValue(ds_main2.getTotalRow());

    }
};



//-------------------------------------------------------------------------
// 그리드 데이터 청구규격 데이터 필터링/ 사용 X
//-------------------------------------------------------------------------
scwin.gr_main_viewChange = function (info) {

};


//-------------------------------------------------------------------------
// Row 변경시 readonly 처리
//-------------------------------------------------------------------------
scwin.ds_main2_onrowpositionchange = function (info) {

    for(i = 0; i < ds_main2.getTotalRow(); i++) {
        if (ds_main2.getCellData(i,"hveqRsltsRegYn") == "1") {
            //gr_main2.Editable = false;
            gr_main2.setCellReadOnly(i, "stvWrkIndictNo", true);
            gr_main2.setCellReadOnly(i, "eqShortNo", true);
            gr_main2.setCellReadOnly(i, "eqKndCd", true);
            gr_main2.setCellReadOnly(i, "bilgNrmCd", true);
            gr_main2.setCellReadOnly(i, "wrkStpCd", true);
            gr_main2.setCellReadOnly(i, "pchsAdjmStdCd", true);
            gr_main2.setCellReadOnly(i, "adptHhCnt", true);
            gr_main2.setCellReadOnly(i, "adptWt", true);
        } else {
            gr_main2.setCellReadOnly(i, "stvWrkIndictNo",false);
            gr_main2.setCellReadOnly(i, "eqShortNo",false);
            gr_main2.setCellReadOnly(i, "eqKndCd",false);
            gr_main2.setCellReadOnly(i, "bilgNrmCd",false);
            gr_main2.setCellReadOnly(i, "wrkStpCd",false);
            gr_main2.setCellReadOnly(i, "pchsAdjmStdCd",false);
            gr_main2.setCellReadOnly(i, "adptHhCnt",false);
            gr_main2.setCellReadOnly(i, "adptWt",false);
        }

        if (ds_main2.getRowStatus(i) == "C") {
            gr_main2.setCellReadOnly(i, "stvWrkIndictNo",false);
        } else {
            gr_main2.setCellReadOnly(i, "stvWrkIndictNo",true);
        }
    }
};


//-------------------------------------------------------------------------
// 청구 규격 필터 때문에 해놓은거임, afterEdit에도 내용은 기재되어있음
//-------------------------------------------------------------------------
scwin.gr_beforeEdit = function (rowIndex, columnIndex, value) {
    scwin.olddata = value;

    columnId = gr_main2.getColumnID(columnIndex);

    switch (columnId) {
        case "bilgNrmCd" :

        for(i = 0; i < ds_main2.getTotalRow(); i++) {
            ds_main2.setCellData(i, "bilgNrmCd", ds_main2.getCellData(i, "bilgNrmCd"));
        }

        ds_LkStepNo2.clearFilter();
        let eqKndCd = ds_main2.getCellData(rowIndex, "eqKndCd");
        ds_LkStepNo2.setColumnFilter({type:"row", colIndex:"upperCd", key:eqKndCd, condition:"and"});

    }
};



