    } else if (colid == "stvWrkIndictNo") { // 작업지시번호 검색
        scwin.f_openCommPopUpGrid(2, gr_main2.getFocusedRowIndex(), "stvWrkIndictNo", ds_main2.getCellData(rowIndex, "stvWrkIndictNo"), 'T', 'T', "ontextimageclick");
    }


};



//-------------------------------------------------------------------------
// 하단 그리드 팝업 / 셀 수정시
//-------------------------------------------------------------------------
scwin.gr_afterEdit = async function (rowIndex, columnIndex, value) {
    let colid = gr_main2.getColumnID(columnIndex);


    // 매입적용시간, 매입적용 중량 , 매입원가 셀은 default value는 설정하였으나 편집시 값 지우고 killfocus되면 asis처럼 0이 남도록 하기 위함
    if (colid == "adptHhCnt" && value == "") {
        ds_main2.setCellData(rowIndex, "adptHhCnt", 0);
    } else if (colid == "adptWt" && value == "") {
        ds_main2.setCellData(rowIndex, "adptWt", 0.000);
    } else if (colid == "pchsPcost" && value == "") {
        ds_main2.setCellData(rowIndex, "pchsPcost", 0);
    } 



    if (colid == "eqShortNo") { // 중기번호 검색
        if(value == "") {
            ds_main2.setCellData(rowIndex, "eqShortNo", "");
            ds_main2.setCellData(rowIndex, "eqCd", "");
            ds_main2.setCellData(rowIndex, "eqNoEqNm", "");
            ds_main2.setCellData(rowIndex, "eqKndCd", "");
            ds_main2.setCellData(rowIndex, "eqNrmCd", "");
            ds_main2.setCellData(rowIndex, "bilgNrmCd", "");
            return;
        }

        if(scwin.olddata == value) {
            return;
        }

        scwin.f_openCommPopUpGrid(1, gr_main2.getFocusedRowIndex(),"eqShortNo", ds_main2.getCellData(rowIndex, "eqShortNo"), 'T', 'T', "onafteredit");
    } else if (colid == "stvWrkIndictNo") { // 작업지시번호 검색

        if(value == "") {
            return;
        }

        if(scwin.olddata == value) {
            return;
        }

        scwin.f_openCommPopUpGrid(2, gr_main2.getFocusedRowIndex(), "stvWrkIndictNo", ds_main2.getCellData(rowIndex, "stvWrkIndictNo"), 'T', 'T', "onafteredit");
    } else if (colid == "eqKndCd") {

        if(value == "") {
            return;
        }

        if(scwin.olddata == value) {
            return;
        }

        for(i = 0; i < ds_main2.getTotalRow(); i++) {
            ds_main2.setCellData(i, "bilgNrmCd", ds_main2.getCellData(i, "bilgNrmCd"));
        }

        ds_LkStepNo2.clearFilter();
        let eqKndCd = ds_main2.getCellData(rowIndex, "eqKndCd");
        ds_LkStepNo2.setColumnFilter({type:"row", colIndex:"upperCd", key:eqKndCd, condition:"and"});

        gr_main2.refreshCell(rowIndex, "bilgNrmCd");
        ds_main2.setCellData(rowIndex, "bilgNrmCd", "");
    } else if(colid == "bilgNrmCd") {

        if(value == "") {
            return;
        }

        if(scwin.olddata == value) {
            return;
        }

        ds_LkStepNo2.clearFilter();
    }


};


//-------------------------------------------------------------------------
// 그리드 팝업셀 분기처리
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = async function (disGubun, rowIndex, pCode, pName, pClose, pAllSearch) {
    let columnIndex = gr_main2.getFocusedColumnIndex();
    columnId = gr_main2.getColumnID(columnIndex);
    let options = {};
    let rtn = "";
    let args = {};
    let arrParam = new Array();


    let evNm = arguments[6] || "";

    if (evNm && $c.win.getEventList(gr_main2, evNm)) {
        scwin.eventCnt++;
    }

    $p.setTimeout(function () {
        scwin.eventCnt = 0;
    }, { delay: 1500 });



    switch (columnId) {


        case "bilgNrmCd" :


        ds_LkStepNo2.clearFilter();
        // 필터걸면 데이터셋에 실제 데이터는 남아있지만 표현 안되기 때문에 한번 더 하는것, 이미 저장된 정보는 수정이 안되는 readonly기 때문에 괜찮음
        // 추후에 같은 건은 linkedDataList로 변경해야함 
        for(i = 0; i < ds_main2.getTotalRow(); i++) {
            ds_main2.setCellData(i, "bilgNrmCd", ds_main2.getCellData(i, "bilgNrmCd"));
        }

        case "pchsAdjmStdCd" :
        if(scwin.eventCnt == 1) {
            if(ds_main2.getCellData(rowIndex, "pchsAdjmStdCd") == "H") {
                gr_main2.removeColumnClass("adptHhCnt_head", "txt-blue");
                gr_main2.removeColumnClass("adptWt_head", "txt-ret");

                gr_main2.setColumnClass("adptHhCnt_head", "txt-red");
                gr_main2.setColumnColor("adptWt_head", "txt-blue");
            }else {
                gr_main2.removeColumnClass("adptHhCnt_head", "txt-red");
                gr_main2.removeColumnClass("adptWt_head", "txt-blue");


                gr_main2.setColumnClass("adptHhCnt_head", "txt-blue");
                gr_main2.setColumnColor("adptWt_head", "txt-red");
            }
        }

        break;

        case "stvWrkIndictNo": // 작업지시번호

            var pCode = "";
			var pName = "";
			var pWrkIndictNo = ds_main2.getCellData(rowIndex, "stvWrkIndictNo");
			var pCvsslMgntNo = "";
		  	if (! await $c.gus.cfValidate([ed_cvsslMgntNo])) { // 본선/작업장구분, 본선관리번호
		  		return;
			}

			pCode = "P"; // 본선/작업장구분
			pCvsslMgntNo = ed_cvsslMgntNo.getValue(); // 본선관리번호

            // 팝업 오픈
           scwin.f_CommonPopUp('retrieveWrkIndictNoList',pCode,pName,"F",5,null,null,null,null,"700",null,null,null,null,null,null,"T1",pWrkIndictNo,pCvsslMgntNo);

            break;


        case "eqShortNo": // 중기 단축번호
            if(scwin.eventCnt == 1) {
                let pDate = ds_main2.getCellData(rowIndex, "wrkDt");
                pCode = ds_main2.getCellData(rowIndex, "eqShortNo");

                // 팝업 옵션 설정
                arrParam[0] = "";    				//assgnLobranCd점소코드
                arrParam[1] = ""; 					//eqKndCd중기종류
                arrParam[2] = "";					//clntCd거래처코드
                arrParam[3] = pDate;   				//usblDt작업계획일자
                arrParam[4] = pCode;		  		//eqNo
                arrParam[5] = "";					//eqNm
                arrParam[6] = 'T';					//T,F구분
                arrParam[7] = 'T';					//T,F구분


                options = {
                    id: "taxPop",
                    popupName: "중기조회",
                    width: 1100,
                    height: 650
                };

                // 팝업 오픈
                rtn = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", options, arrParam);

                if (rtn != null && rtn != undefined) {
                    ds_main2.setCellData(rowIndex, "eqShortNo", rtn[0]);
                    ds_main2.setCellData(rowIndex, "eqCd", rtn[12]);
                    ds_main2.setCellData(rowIndex, "eqNoEqNm", rtn[1]);
                    ds_main2.setCellData(rowIndex, "eqKndCd", rtn[15]);
                    ds_main2.setCellData(rowIndex, "eqNrmCd", rtn[11]);
                    ds_main2.setCellData(rowIndex, "bilgNrmCd", rtn[11]);
                    gr_main2.setFocusedCell(rowIndex, "eqKndCd");
                } else if(ds_main2.getCellData(rowIndex,columnId) == "") {
                    ds_main2.setCellData(rowIndex, "eqShortNo", "");
                    ds_main2.setCellData(rowIndex, "eqCd", "");
                    ds_main2.setCellData(rowIndex, "eqNoEqNm", "");
                    ds_main2.setCellData(rowIndex, "eqKndCd", "");
                    ds_main2.setCellData(rowIndex, "eqNrmCd", "");
                    ds_main2.setCellData(rowIndex, "bilgNrmCd", "");

                }

            }
            break;


        default:
            break
    }
}

